func:
const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};
const infoMap = global.get('info_map') || {};

infoMap[serial] = {
    type:             d.device_type || d.type || '',
    production_date:  d.production_date || '',
    hw_version:       d.hw_version || 0,
    serial_number:    d.serial_number || serial
};

global.set('info_map', infoMap);
return null;

const p = msg.topic.split('/');
const serial = p[3];
const d = msg.payload || {};
const settingsMap = global.get('settings_cache') || {};

settingsMap[serial] = {
    serial:                      d.serial               || serial,
    battery_type_index:          d.battery_type_index         || 0,
    capacity_ah:                 d.capacity_ah                || 100,
    lvd_voltage_mv:              d.lvd_voltage_mv             || 11000,
    lvd_mode_voltage:            d.lvd_mode_voltage           || false,
    night_mode_index:            d.night_mode_index           || 1,
    evening_minutes_mn:          d.evening_minutes_mn         || 0,
    morning_minutes_mn:          d.morning_minutes_mn         || 0,
    night_threshold_mv:          d.night_threshold_mv         || 11500,
    night_mode_dimming_index:    d.night_mode_dimming_index   || 0,
    evening_minutes_dimming_mn:  d.evening_minutes_dimming_mn || 0,
    morning_minutes_dimming_mn:  d.morning_minutes_dimming_mn || 0,
    dimming_pct:                 d.dimming_pct                || 100,
    base_dimming_pct:            d.base_dimming_pct           || 30,
    dali_power_enable:           d.dali_power_enable          || false,
    alc_dimming_enable:          d.alc_dimming_enable         || false
};
global.set('settings_cache', settingsMap);

// Output 0: re-trigger device select if this is the currently selected device
// Output 1: always refresh dropdown options
const selected = flow.get('selected_serial');
const repopulate = (selected === serial) ? { payload: serial } : null;
return [repopulate, {}];

const p = msg.topic.split('/');
const serial = p[3];
const zone = p[1];
const isOnline = msg.payload.toString().trim() === '1';
const key = 'online_' + serial;
const wasOnline = context.get(key);
context.set(key, isOnline);

const onlineMap = global.get('online_map') || {};
onlineMap[serial] = { online: isOnline, ts: new Date().toISOString() };
global.set('online_map', onlineMap);

if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [{ payload: {
        severity: 'critical', condition: 'Device offline',
        emailNeeded: true, serial, zone, ts,
        subject: '[MPPT CRITICAL] ' + serial + ' offline',
        body: 'Device ' + serial + ' (zone: ' + zone + ') went offline at ' + ts
    }}];
}
if (isOnline && wasOnline === false) {
    node.log(serial + ' back online');
}
return null;

if (!msg.payload || !msg.payload.subject) return null;
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return null;
msg.zone       = p[1];
msg.gateway_id = p[2];
msg.serial     = p[3];

const d = msg.payload || {};

const infoMap = global.get('info_map') || {};
const info    = infoMap[msg.serial] || {};

msg.gen = {
    hw_version:         d.hw_version         || info.hw_version || 0,
    serial_number:      d.serial             || info.serial_number || msg.serial,
    firmware_version:   d.firmware_version   || 0,
    internal_temp_c:    d.internal_temp_c    || 0,
    external_temp_c:    d.external_temp_c    || 0,
    controller_op_days: d.controller_op_days || 0,
    timestamp:          Math.floor(Date.now() / 1000)
};

msg.bat = {
    battery_voltage_mv:               d.battery_voltage_mv       || 0,
    battery_soc_pct:                 d.battery_soc_pct         || 0,
    charge_current_a:        d.charge_current_a        || 0,
    charge_power_w:          d.charge_power_w          || 0,
    end_of_charge_voltage_mv: d.end_of_charge_voltage_mv || 0,
    charge_mode:             d.charge_mode             || 'unknown',
    is_night:                !!d.is_night,
    bat_op_days:             d.bat_op_days             || 0,
    energy_in_daily_wh:      d.energy_in_daily_wh      || 0,
    energy_out_daily_wh:     d.energy_out_daily_wh     || 0,
    energy_retained_wh:      d.energy_retained_wh      || 0,
    detected:                !!d.battery_detected
};

msg.load = {
    load_on:        !!d.load_on,
    night_mode:     !!d.night_mode,
    lvd_active:     !!d.lvd_active,
    user_disconnect:!!d.user_disconnect,
    over_current:   !!d.over_current,
    load_current_ma10:      d.load_current_ma10 || 0,
    load_power_w:        d.load_power_w   || 0
};

msg.pv = {
    pv_voltage_mv:        d.pv_voltage_mv        || 0,
    pv_target_voltage_mv: d.pv_target_voltage_mv || 0,
    detected:         !!d.pv_detected
};

msg.night = {
    time_since_dusk_min: d.time_since_dusk_min || 0,
    average_length_min:  d.average_length_min  || 0
};

msg.led = {
    led_voltage_mv:   d.led_voltage_mv || 0,
    led_current_ma10:   d.led_current_ma10 * 10 || 0,
    power_w:     d.led_power_w   || 0,
    status:      d.led_status    || 'Unknown',
    dali_active: !!d.dali_active
};

msg.load.state_mask = d.load_state_mask || 0;
msg.bat.charge_state_mask = d.charge_state_mask || 0;
msg.gen.flags = d.flags || 0;
const f = d.fault_mask;
msg.faults = {
    battery_over_voltage:   (f & 0x01) ? 1 : 0,
    pv_over_voltage:        (f & 0x02) ? 1 : 0,
    controller_over_temp:   (f & 0x04) ? 1 : 0,
    charge_over_current:    (f & 0x08) ? 1 : 0,
    lvd_active:             (f & 0x10) ? 1 : 0,
    over_discharge_current: (f & 0x20) ? 1 : 0,
    battery_over_temp:      (f & 0x40) ? 1 : 0,
    battery_under_temp:     (f & 0x80) ? 1 : 0,   
};

msg.hw_version = String(msg.gen.hw_version);

const fleet = global.get('fleet') || {};
fleet[msg.serial] = {
    serial: msg.serial, zone: msg.zone, gateway_id: msg.gateway_id,
    hw_version: msg.hw_version,
    bat: msg.bat, load: msg.load, pv: msg.pv, faults: msg.faults,
    gen: msg.gen, ts: msg.gen.timestamp
};
global.set('fleet', fleet);
return msg;

const bat = msg.bat, load = msg.load, faults = msg.faults;
const serial = msg.serial, zone = msg.zone;
const ts = msg.gen.timestamp || new Date().toISOString();

const checks = [
    { cond: bat.soc_pct >= 10 && bat.soc_pct < 20, sev: 'warning',  email: false,
      msg: 'Battery SOC low (' + bat.soc_pct + '%)' },
    { cond: bat.soc_pct < 10,                       sev: 'critical', email: true,
      msg: 'Battery SOC critical (' + bat.soc_pct + '%)' },
    { cond: !!(faults.lvd_active || load.lvd_active), sev: 'critical', email: true,
      msg: 'LVD active' },
    { cond: !!faults.battery_over_voltage,  sev: 'critical', email: true, msg: 'Battery over voltage' },
    { cond: !!faults.over_discharge_current,sev: 'critical', email: true, msg: 'Over discharge current' },
    { cond: !!faults.battery_over_temp,     sev: 'critical', email: true, msg: 'Battery over temperature' },
    { cond: !!faults.battery_under_temp,    sev: 'critical', email: true, msg: 'Battery under temperature' },
];

const out = checks.filter(c => c.cond).map(c => ({ payload: {
    severity: c.sev, condition: c.msg, emailNeeded: c.email,
    serial, zone, ts,
    subject: '[MPPT ' + c.sev.toUpperCase() + '] ' + serial + ' - ' + c.msg,
    body: 'Device: ' + serial + '\nZone: ' + zone + '\nCondition: ' + c.msg + '\nTimestamp: ' + ts
}}));

if (!out.length) return null;
const email = out.filter(m => m.payload.emailNeeded);
return [ email.length ? email : null, out ];

const f = msg.faults || {};
const tags = {
    zone: msg.zone, gateway_id: msg.gateway_id,
    serial: msg.serial, hw_version: msg.hw_version || '-1'
};
const fields = f;
msg.payload = [fields, tags];
return msg;

const p = msg.topic.split("/");
if (p.length < 6) return null;
const zone = p[1], gateway = p[2], serial = p[3], sub = p[5];
const dl = msg.payload;
const infoMap = global.get("info_map") || {};
const info = infoMap[serial] || {};
const hw_version = String(info.hw_version || 0);
const ct = { serial, gateway_id: gateway, zone, hw_version };

function unpackStateFlags(sf) {
    return {
        load_disconnect:  (sf >> 0) & 1, full_charge:       (sf >> 1) & 1,
        pv_over_current:  (sf >> 2) & 1, load_over_current: (sf >> 3) & 1,
        bat_over_voltage: (sf >> 4) & 1, low_soc:           (sf >> 5) & 1,
        temp_pv_over:     (sf >> 6) & 1, temp_pv_low:       (sf >> 7) & 1,
        temp_load_over:   (sf >> 8) & 1
    };
}

function mapEntry(e, i, indexKey) {
    return {
        [indexKey]:      e.index || 0,
        vbat_min_mv:      e.vbat_min_mv || 0,
        vbat_max_mv:      e.vbat_max_mv || 0,
        vpv_min_mv:       e.vpv_min_mv || 0,
        vpv_max_mv:       e.vpv_max_mv || 0,
        ah_charge_mah:       e.ah_charge_mah || 0,
        ah_load_mah:         e.ah_load_mah || 0,
        soc_pct:         e.soc_pct || 0,
        ext_temp_max_c:  e.ext_temp_max_c || 0,
        ext_temp_min_c:  e.ext_temp_min_c || 0,
        nightlength_min: e.nightlength_min || 0,
        il_max_ma10:        e.il_max_ma10 || 0,
        ipv_max_ma10:       e.ipv_max_ma10 || 0,
        ...unpackStateFlags(e.state_flags || 0)
    };
}

if (sub === "summary") {
    return [{ payload: [{
        recorded_days:              dl.recorded_days  || 0,
        days_with_lvd:              dl.days_with_lvd  || 0,
        months_without_full_charge: dl.months_without_full_charge || 0,
        avg_morning_soc_pct:        dl.avg_morning_soc_pct  || 0,
        total_ah_charge_mah:        dl.total_ah_charge_mah  || 0,
        total_ah_load_mah:          dl.total_ah_load_mah  || 0
    }, ct] }, null, null];
}

if (sub === "daily") {
    const msgs = (dl.daily_logs || []).map((e, i) => ({
        payload: [mapEntry(e, i, "day_num"), Object.assign({ day_index: String(e.index || i + 1) }, ct)]
    }));
    return [null, msgs.length ? msgs : null, null];
}

if (sub === "monthly") {
    const msgs = (dl.monthly_logs || []).map((e, i) => ({
        payload: [mapEntry(e, i, "month_num"), Object.assign({ month_index: String(e.index || i + 1) }, ct)]
    }));
    return [null, null, msgs.length ? msgs : null];
}

return null;

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const serials = Object.keys(fleet).sort();

if (!serials.length) {
    const empty = '<p style="color:#94a3b8;padding:24px;text-align:center;font-style:italic">No devices detected on the network yet.</p>';
    return [{ payload: empty }, { payload: empty }];
}

let totalDevices = serials.length;
let onlineCount = 0;
let faultCount = 0;
let totalSoc = 0;
let totalCharge = 0;

for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s];
    if (!om || om.online) onlineCount++;
    if (d.faults && (d.faults.any_fault || Object.values(d.faults).some(v => v === 1 || v === true))) faultCount++;
    totalSoc += (d.bat && typeof d.bat.soc_pct === 'number') ? d.bat.soc_pct : 0;
    totalCharge += (d.bat && typeof d.bat.charge_power_w === 'number') ? d.bat.charge_power_w : 0;
}

const avgSoc = totalDevices ? Math.round(totalSoc / totalDevices) : 0;
const offlineCount = totalDevices - onlineCount;

function statCard(label, value, sub, color) {
    return '<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; background:rgba(30, 41, 59, 0.7); border:1px solid #334155; border-radius:12px; padding:20px; margin:8px; min-width:160px; flex:1; box-shadow:0 4px 6px -1px rgb(0 0 0 / 0.1)">' +
        '<div style="font-size:32px; font-weight:800; color:' + color + '; line-height:1">' + value + '</div>' +
        '<div style="font-size:13px; font-weight:600; color:#94a3b8; margin-top:8px; text-transform:uppercase; letter-spacing:0.05em">' + label + '</div>' +
        (sub ? '<div style="font-size:11px; color:#64748b; margin-top:2px">' + sub + '</div>' : '') +
        '</div>';
}

const summaryHtml = '<div style="display:flex; flex-wrap:wrap; justify-content:space-between; width:100%">' +
    statCard('Devices', totalDevices, 'total', '#3b82f6') +
    statCard('Online', onlineCount, offlineCount + ' offline', onlineCount === totalDevices ? '#22c55e' : '#f59e0b') +
    statCard('Avg SOC', avgSoc + '%', '', avgSoc > 50 ? '#22c55e' : avgSoc > 20 ? '#f59e0b' : '#ef4444') +
    statCard('Charge', Math.round(totalCharge) + ' W', 'fleet total', '#3b82f6') +
    statCard('Faults', faultCount, faultCount ? 'devices with issues' : 'all clear', faultCount ? '#ef4444' : '#22c55e') +
    '</div>';

let rows = '';
for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s] || { online: true };
    const online = om.online;
    const soc = (d.bat && d.bat.soc_pct) || 0;
    const vbat = (d.bat && d.bat.voltage_v) || 0;
    const icharge = (d.bat && d.bat.charge_current_a) || 0;
    const iload = (d.load && d.load.current_a) || 0;
    const faults = d.faults && (d.faults.any_fault || Object.values(d.faults).some(v => v === 1 || v === true));

    rows += '<tr style="border-bottom:1px solid #334155">' +
        '<td style="padding:12px 8px"><div style="display:flex; align-items:center"><div style="width:8px; height:8px; border-radius:50%; background:' + (online ? '#22c55e' : '#ef4444') + '; margin-right:10px"></div>' +
        '<div><div style="font-weight:600; color:#f1f5f9">' + s + '</div><div style="font-size:10px; color:#64748b">' + (d.zone || 'N/A') + ' / ' + (d.gateway_id || 'N/A') + '</div></div></div></td>' +
        '<td style="padding:12px 8px; text-align:center"><div style="width:100%; background:#334155; height:6px; border-radius:3px; margin-bottom:4px">' +
        '<div style="width:' + soc + '%; background:' + (soc > 50 ? '#22c55e' : soc > 20 ? '#f59e0b' : '#ef4444') + '; height:100%; border-radius:3px"></div></div>' +
        '<span style="font-size:12px; font-weight:700; color:#f1f5f9">' + soc + '%</span></td>' +
        '<td style="padding:12px 8px; text-align:center; color:#f1f5f9">' + vbat.toFixed(1) + 'V</td>' +
        '<td style="padding:12px 8px; text-align:center; color:#3b82f6; font-weight:600">' + icharge.toFixed(1) + 'A</td>' +
        '<td style="padding:12px 8px; text-align:center; color:#f59e0b; font-weight:600">' + iload.toFixed(1) + 'A</td>' +
        '<td style="padding:12px 8px; text-align:center">' + (faults ? '<span style="background:#ef4444; color:white; padding:2px 6px; border-radius:4px; font-size:10px; font-weight:800">FAULT</span>' : '<span style="color:#22c55e; font-size:18px">✓</span>') + '</td></tr>';
}

const tableHtml = '<table style="width:100%; border-collapse:collapse; color:#94a3b8; font-size:13px"><thead><tr style="text-align:left; border-bottom:2px solid #334155">' +
    '<th style="padding:8px; font-weight:600; color:#cbd5e1">Device / Zone</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">SOC</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Bat V</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Charge</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Load</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Status</th></tr></thead><tbody>' + rows + '</tbody></table>';

return [{ payload: summaryHtml }, { payload: tableHtml }];

const serial = msg.payload;
const out = new Array(18).fill(null);

if (!serial || typeof serial !== 'string') {
    flow.set('selected_serial', null);

    out[0] = {
        payload: `<div style="padding:60px 20px;text-align:center;color:#64748b;font-size:15px;">Select a device from the dropdown above</div>`
    };

    out[17] = { payload: '' };

    node.send(out);
    return null;
}

flow.set('selected_serial', serial);
flow.set('w__dirty', false);

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const settingsMap = global.get('settings_cache') || {};
const infoMap = global.get('info_map') || {};

const dev = fleet[serial] || {};
const s = settingsMap[serial] || null;
const info = infoMap[serial] || {};
const online = onlineMap[serial] ? onlineMap[serial].online !== false : true;

const statusColor = online ? '#22c55e' : '#ef4444';

out[0] = {
    payload: `
<div style="background:#1e2937;padding:18px;border-radius:8px;margin-bottom:16px;">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;">
        <div style="width:16px;height:16px;border-radius:50%;background:${statusColor};"></div>
        <span style="font-size:26px;font-weight:700;">${serial}</span>
        <span style="color:${statusColor};font-weight:700;">${online ? '● ONLINE' : '○ OFFLINE'}</span>
    </div>

    <div style="display:grid;grid-template-columns:120px 1fr;gap:8px;font-size:14.5px;line-height:1.6;">
        <div style="color:#64748b;">Model</div><div style="color:#e2e8f0;">${info.type || 'MPPT'} V${info.hw_version || '?'}</div>
        <div style="color:#64748b;">Produced</div><div style="color:#e2e8f0;">${info.production_date || '—'}</div>
        <div style="color:#64748b;">Zone</div><div style="color:#e2e8f0;">${dev.zone || 'default'}</div>
        <div style="color:#64748b;">Gateway</div><div style="color:#e2e8f0;">${dev.gateway_id || '—'}</div>
    </div>
</div>`
};

const BAT = ['AGM', 'Liquid', 'LiFePO4 High Temp', 'LiFePO4 Med Temp', 'LiFePO4 Low Temp'];
const MODE = ['Off', 'D2D', 'DD', 'MN'];

out[17] = {
    payload: s ? `
<div style="background:#1e2937;padding:18px;border-radius:8px;">
    <div style="font-size:15px;font-weight:700;color:#e2e8f0;margin-bottom:16px;">DEVICE CONFIGURATION</div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px 30px;font-size:14.5px;">
        <div><span style="color:#64748b;">Battery Type</span><br><strong>${BAT[s.battery_type_index] ?? s.battery_type_index}</strong></div>
        <div><span style="color:#64748b;">Capacity</span><br><strong>${s.capacity_ah}</strong> Ah</div>

        <div><span style="color:#64748b;">LVD</span><br><strong>${(s.lvd_voltage_mv / 1000).toFixed(1)} V</strong></div>
        <div><span style="color:#64748b;">LVD Mode</span><br><strong>${s.lvd_mode_voltage ? 'Voltage' : 'SOC'}</strong></div>

        <div><span style="color:#64748b;">Night Mode</span><br><strong>${MODE[s.night_mode_index] ?? s.night_mode_index}</strong></div>
        <div><span style="color:#64748b;">Evening</span><br><strong>${s.evening_minutes_mn} min</strong></div>
        <div><span style="color:#64748b;">Morning</span><br><strong>${s.morning_minutes_mn} min</strong></div>

        <div><span style="color:#64748b;">Night Thresh</span><br><strong>${(s.night_threshold_mv / 1000).toFixed(1)} V</strong></div>

        <div><span style="color:#64748b;">Dim Mode</span><br><strong>${MODE[s.night_mode_dimming_index] ?? s.night_mode_dimming_index}</strong></div>
        <div><span style="color:#64748b;">Dimming</span><br><strong>${s.dimming_pct} %</strong></div>
        <div><span style="color:#64748b;">Base Dim</span><br><strong>${s.base_dimming_pct} %</strong></div>

        <div><span style="color:#64748b;">DALI</span><br><strong>${s.dali_power_enable === true ? '✅ On' : '❌ Off'}</strong></div>
        <div><span style="color:#64748b;">ALC</span><br><strong>${s.alc_dimming_enable === true ? '✅ On' : '❌ Off'}</strong></div>
    </div>
</div>
` : `
<div style="background:#1e2937;padding:80px 20px;text-align:center;color:#64748b;border-radius:8px;">
    No settings cached yet<br><small>Click "Send Settings" to load</small>
</div>`
};

if (s) {
    const map = [
        ['battery_type_index', 0, 'string'],
        ['capacity_ah', 100],
        ['lvd_voltage_mv', 11000],
        ['lvd_mode_voltage', false],
        ['night_mode_index', 1, 'string'],
        ['evening_minutes_mn', 0],
        ['morning_minutes_mn', 0],
        ['night_threshold_mv', 11500],
        ['night_mode_dimming_index', 0],
        ['evening_minutes_dimming_mn', 0],
        ['morning_minutes_dimming_mn', 0],
        ['dimming_pct', 0],
        ['base_dimming_pct', 0],
        ['dali_power_enable', false],
        ['alc_dimming_enable', false]
    ];

    map.forEach((m, i) => {
        const key = m[0];
        const def = m[1];
        let val = s[key];

        if (val === undefined) val = def;

        if (typeof def === 'string') val = String(val);
        if (typeof def === 'boolean') val = val === true;

        out[i + 1] = {
            payload: val,
            _populate: true
        };
    });
}

node.send(out);
return null;

flow.set('w_' + msg.topic, msg.payload);
if (!msg._populate) {
    flow.set('w__dirty', true);
}
return null;

if (msg.topic === 'send')   return [msg, null];
if (msg.topic === 'reload') return [null, msg];
return null;

var serial = flow.get('selected_serial');
if (!serial) return null;
// Re-trigger On device select with the current serial
msg.payload = serial;
return msg;

const serial = flow.get('selected_serial');
if (!serial) return null;

const fleet = global.get('fleet') || {};
const settingsMap = global.get('settings_cache') || {};
const current = settingsMap[serial]|| {};

const dev = fleet[serial] || {};
const zone = dev.zone || 'default';
const gw = dev.gateway_id || 'unknown';

const get = (key) => {
    const v = flow.get('w_w-' + key);
    if (v === undefined || v === null || v === '') return undefined;
    return v;
};

const setIfChanged = (out, key, val, oldVal) => {
    if (val !== oldVal) out[key] = val;
};

const setSettings = {};

setIfChanged(setSettings, 'battery_type_index',
    Number(get('bat-type')),
    current.battery_type_index
);

setIfChanged(setSettings, 'capacity_ah',
    Number(get('cap-ah')),
    current.capacity_ah
);

setIfChanged(setSettings, 'lvd_voltage_mv',
    Number(get('lvd-v')),
    current.lvd_voltage_mv
);

setIfChanged(setSettings, 'night_threshold_mv',
    Number(get('night-thresh')),
    current.night_threshold_mv
);

setIfChanged(setSettings, 'night_mode_index',
    get('night-mode'),
    current.night_mode_index
);

setIfChanged(setSettings, 'evening_minutes_mn',
    get('eve-min'),
    current.evening_minutes_mn
);

setIfChanged(setSettings, 'morning_minutes_mn',
    get('morn-min'),
    current.morning_minutes_mn
);

setIfChanged(setSettings, 'night_mode_dimming_index',
    get('dim-mode'),
    current.night_mode_dimming_index
);

setIfChanged(setSettings, 'evening_minutes_dimming_mn',
    get('dim-eve-min'),
    current.evening_minutes_dimming_mn
);

setIfChanged(setSettings, 'morning_minutes_dimming_mn',
    get('dim-morn-min'),
    current.morning_minutes_dimming_mn
);

setIfChanged(setSettings, 'dimming_pct',
    get('dim-pct'),
    current.dimming_pct
);

setIfChanged(setSettings, 'base_dimming_pct',
    get('base-dim-pct'),
    current.base_dimming_pct
);

const dali = !!get('dali');
const alc = !!get('alc');

let advanced_flags = current.advanced_flags ?? 0;

advanced_flags &= ~(1 << 0);
advanced_flags &= ~(1 << 1);

if (dali) advanced_flags |= (1 << 0);
if (alc) advanced_flags |= (1 << 1);

setSettings.advanced_flags = advanced_flags;

const requestId = `${serial}_${Date.now()}`;

msg.topic = `mppt/${zone}/${gw}/${serial}/cmd`;
msg.payload = {
    serial,
    request_id: requestId,
    set_settings: setSettings
};

const changeCount = Object.keys(setSettings).length;
const ts = new Date().toLocaleTimeString();

const entry = `
<div style="font-size:12px; padding:4px 0; border-bottom:1px solid #334155">
    <span style="color:#64748b">${ts}</span>
    <span style="color:#3b82f6; font-weight:600">SEND</span>
    ${serial} — ${requestId}
    <span style="color:#eab308">(${changeCount} changed)</span>
</div>`;

flow.set('cmd_log', entry + (flow.get('cmd_log') || ''));
flow.set('w__dirty', false);

return msg;

var log = flow.get('cmd_log') || '<span style="color:#64748b;font-style:italic">No commands sent yet.</span>';

msg.payload =
'<div style="width:100%;min-width:100%;font-family:monospace;font-size:14px;line-height:1.4;padding:10px;box-sizing:border-box;border:1px solid #e5e7eb;border-radius:6px;background:#fff;">'
+ log +
'</div>';

return msg;

const p      = msg.topic.split('/');
const serial = p.length >= 4 ? p[3] : '?';
const ts     = new Date().toLocaleTimeString();
const pl     = msg.payload || {};

const ok     = pl.ok;
const reason = pl.reason || '';
const reqId  = pl.request_id || '';

const color = ok ? '#4ade80' : '#f87171';
const label = ok ? 'ACK ✓'  : 'ACK ✗';
const idStr = reqId ? ` <span style="color:#475569">[${reqId.split('_').pop()}]</span>` : '';

const entry =
    `<div style="font-size:12px;padding:4px 0;border-bottom:1px solid #1e293b">` +
    `<span style="color:#475569">${ts}</span> ` +
    `<span style="color:${color};font-weight:700">${label}</span> ` +
    `<span style="color:#94a3b8">${serial}</span>${idStr}` +
    `${reason ? '<span style="color:#64748b"> - ' + reason + '</span>' : ''}` +
    `</div>`;

const log = flow.get('cmd_log') || '';
flow.set('cmd_log', entry + log);

msg.payload =
    `<div style="font-family:monospace;max-height:260px;overflow-y:auto;font-size:12px">` +
    flow.get('cmd_log') + '</div>';
return msg;

var fleet = global.get('fleet') || {};

var opts = Object.keys(fleet)
    .sort()
    .map(function(s) {
        var dev = fleet[s] || {};
        var zone = dev.zone || 'default';
        var onlineMap = global.get('online_map') || {};
        var isOnline = onlineMap[s] ? onlineMap[s].online !== false : true;
        var icon = isOnline ? ' ●' : ' ○';
        return {
            value: s,
            label: s + ' [' + zone + ']' + icon
        };
    });

opts.unshift({ value: "", label: "-- Select Device --" });

var optsStr = JSON.stringify(opts);
if (optsStr === context.get('lastOpts')) return null;
context.set('lastOpts', optsStr);

msg.payload = opts;
msg.topic = "options";
msg.ui_update = { options: opts };

return msg;

const p = msg.topic.split('/');
const serial = p[3];
const d = msg.payload || {};
const settingsMap = global.get('settings_cache') || {};

settingsMap[serial] = {
    serial: d.serial || serial,

    battery_type_index: d.battery_type_index ?? 0,
    capacity_ah: d.capacity_ah ?? 0,

    lvd_voltage_mv: d.lvd_voltage_mv ?? 0,
    lvd_mode_voltage: d.lvd_mode_voltage ?? false,

    night_mode_index: d.night_mode_index ?? 1,
    evening_minutes_mn: d.evening_minutes_mn ?? 0,
    morning_minutes_mn: d.morning_minutes_mn ?? 0,

    night_threshold_mv: d.night_threshold_mv ?? 0,

    night_mode_dimming_index: d.night_mode_dimming_index ?? 0,
    evening_minutes_dimming_mn: d.evening_minutes_dimming_mn ?? 0,
    morning_minutes_dimming_mn: d.morning_minutes_dimming_mn ?? 0,

    dimming_pct: d.dimming_pct ?? 0,
    base_dimming_pct: d.base_dimming_pct ?? 0,

    dali_power_enable: d.dali_power_enable ?? false,
    alc_dimming_enable: d.alc_dimming_enable ?? false
};

global.set('settings_cache', settingsMap);

const selected = flow.get('selected_serial');

const repopulate = (selected === serial)
    ? { payload: serial }
    : null;

return [repopulate, {}];

const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};
const infoMap = global.get('info_map') || {};

infoMap[serial] = {
    type:             d.device_type || d.type || '',
    production_date:  d.production_date || '',
    hw_version:       d.hw_version || 0,
    serial_number:    d.serial_number || serial
};

global.set('info_map', infoMap);
return null;
